package com.cisco.quizapp.data.local

import com.cisco.quizapp.data.local.entity.Question
import com.cisco.quizapp.data.local.entity.Topic
import com.cisco.quizapp.data.repository.QuizRepository
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class DatabaseSeeder @Inject constructor(
    private val repository: QuizRepository
) {

    /** Seeds the database only when it is empty. Safe to call on every app launch. */
    suspend fun seedIfEmpty() {
        if (repository.getTopicCount() > 0) return
        val topicIds = repository.insertTopics(topics)
        val idMap = topics.mapIndexed { index, topic -> topic.name to topicIds[index] }.toMap()
        val questions = buildQuestions(idMap)
        repository.insertQuestions(questions)
    }

    // ── Topic definitions ─────────────────────────────────────────────────────

    private val topics = listOf(
        Topic(name = "OSI Model",             description = "Seven-layer reference model for network communication.",                      iconName = "ic_osi",      difficultyLevel = 1),
        Topic(name = "TCP vs UDP",            description = "Comparing reliable TCP and fast UDP transport protocols.",                    iconName = "ic_tcp",      difficultyLevel = 1),
        Topic(name = "IP Addressing",         description = "IPv4 addressing, classes, and subnetting fundamentals.",                     iconName = "ic_subnet",   difficultyLevel = 1),
        Topic(name = "DNS",                   description = "Domain Name System — translates hostnames to IP addresses.",                 iconName = "ic_dns",      difficultyLevel = 1),
        Topic(name = "DHCP",                  description = "Dynamic Host Configuration Protocol — automatic IP address assignment.",     iconName = "ic_dhcp",     difficultyLevel = 1),
        Topic(name = "Switching & VLANs",     description = "Ethernet switching, MAC addressing, and virtual LAN segmentation.",         iconName = "ic_vlan",     difficultyLevel = 1),
        Topic(name = "Routing Basics",        description = "How routers forward packets and basic routing concepts.",                    iconName = "ic_routing",  difficultyLevel = 1),
        Topic(name = "Firewalls & ACLs",      description = "Filtering network traffic with firewalls and access control lists.",        iconName = "ic_firewall", difficultyLevel = 1)
    )

    // ── Question definitions ──────────────────────────────────────────────────

    @Suppress("LongMethod")
    private fun buildQuestions(idMap: Map<String, Long>): List<Question> {
        val list = mutableListOf<Question>()

        // ── OSI Model ─────────────────────────────────────────────────────────
        val osi = idMap.getValue("OSI Model")
        list += listOf(
            Question(topicId = osi, questionText = "How many layers does the OSI model have?", optionA = "4", optionB = "5", optionC = "7", optionD = "9", correctAnswer = "C", explanation = "The OSI model defines 7 layers: Physical, Data Link, Network, Transport, Session, Presentation, and Application.", difficulty = 1),
            Question(topicId = osi, questionText = "Which OSI layer is responsible for physical transmission of bits over a medium?", optionA = "Data Link", optionB = "Physical", optionC = "Network", optionD = "Transport", correctAnswer = "B", explanation = "Layer 1 (Physical) handles the raw bit stream over the physical medium such as cables or radio signals.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer of the OSI model handles MAC addresses?", optionA = "Network", optionB = "Transport", optionC = "Physical", optionD = "Data Link", correctAnswer = "D", explanation = "Layer 2 (Data Link) uses MAC addresses to deliver frames within the same local network segment.", difficulty = 1),
            Question(topicId = osi, questionText = "IP addressing and routing occur at which OSI layer?", optionA = "Transport", optionB = "Network", optionC = "Data Link", optionD = "Session", correctAnswer = "B", explanation = "Layer 3 (Network) is responsible for logical addressing (IP) and routing packets between networks.", difficulty = 1),
            Question(topicId = osi, questionText = "TCP and UDP operate at which OSI layer?", optionA = "Network", optionB = "Session", optionC = "Transport", optionD = "Application", correctAnswer = "C", explanation = "Layer 4 (Transport) provides end-to-end communication services including TCP and UDP.", difficulty = 1),
            Question(topicId = osi, questionText = "Which OSI layer establishes, manages, and terminates sessions between applications?", optionA = "Transport", optionB = "Presentation", optionC = "Session", optionD = "Application", correctAnswer = "C", explanation = "Layer 5 (Session) manages dialogues (sessions) between computers.", difficulty = 1),
            Question(topicId = osi, questionText = "Data encryption and compression are functions of which OSI layer?", optionA = "Application", optionB = "Session", optionC = "Transport", optionD = "Presentation", correctAnswer = "D", explanation = "Layer 6 (Presentation) handles data translation, encryption, and compression.", difficulty = 1),
            Question(topicId = osi, questionText = "HTTP, FTP, and SMTP operate at which OSI layer?", optionA = "Session", optionB = "Presentation", optionC = "Transport", optionD = "Application", correctAnswer = "D", explanation = "Layer 7 (Application) provides network services directly to end-user applications.", difficulty = 1),
            Question(topicId = osi, questionText = "What is the PDU (Protocol Data Unit) name at the Data Link layer?", optionA = "Packet", optionB = "Segment", optionC = "Frame", optionD = "Bit", correctAnswer = "C", explanation = "The Data Link layer encapsulates data into frames, which include MAC addresses and error-checking fields.", difficulty = 1),
            Question(topicId = osi, questionText = "What is the PDU name at the Network layer?", optionA = "Frame", optionB = "Packet", optionC = "Segment", optionD = "Datagram", correctAnswer = "B", explanation = "The Network layer encapsulates data into packets that contain source and destination IP addresses.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer converts data into bits for transmission?", optionA = "Data Link", optionB = "Presentation", optionC = "Physical", optionD = "Network", correctAnswer = "C", explanation = "The Physical layer converts frames into electrical, optical, or radio signals (bits) for transmission.", difficulty = 1),
            Question(topicId = osi, questionText = "A switch operates primarily at which OSI layer?", optionA = "Layer 1", optionB = "Layer 2", optionC = "Layer 3", optionD = "Layer 4", correctAnswer = "B", explanation = "Switches operate at Layer 2 (Data Link) and use MAC addresses to forward frames.", difficulty = 1),
            Question(topicId = osi, questionText = "A router operates primarily at which OSI layer?", optionA = "Layer 1", optionB = "Layer 2", optionC = "Layer 3", optionD = "Layer 4", correctAnswer = "C", explanation = "Routers operate at Layer 3 (Network) and use IP addresses to route packets between networks.", difficulty = 1),
            Question(topicId = osi, questionText = "Which OSI layer is closest to the end user?", optionA = "Physical", optionB = "Network", optionC = "Transport", optionD = "Application", correctAnswer = "D", explanation = "Layer 7 (Application) is the topmost layer and interacts directly with user-facing software.", difficulty = 1),
            Question(topicId = osi, questionText = "In which order does data travel when sending from a host (top-down)?", optionA = "Physical → Application", optionB = "Application → Physical", optionC = "Transport → Network → Application", optionD = "Network → Transport → Physical", correctAnswer = "B", explanation = "Data is encapsulated as it travels down from the Application layer (7) to the Physical layer (1) on the sending host.", difficulty = 1),
            Question(topicId = osi, questionText = "What process adds a header to data as it moves down the OSI layers?", optionA = "Segmentation", optionB = "Encapsulation", optionC = "Multiplexing", optionD = "Tunneling", correctAnswer = "B", explanation = "Encapsulation wraps data with protocol-specific headers (and sometimes trailers) at each layer.", difficulty = 1),
            Question(topicId = osi, questionText = "The process of removing headers as data moves up the OSI layers is called?", optionA = "Fragmentation", optionB = "Encapsulation", optionC = "De-encapsulation", optionD = "Multiplexing", correctAnswer = "C", explanation = "De-encapsulation strips headers at each layer as data travels up to the receiving application.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer provides flow control and error recovery for end-to-end communication?", optionA = "Data Link", optionB = "Session", optionC = "Transport", optionD = "Network", correctAnswer = "C", explanation = "The Transport layer (Layer 4) handles end-to-end flow control and error recovery (e.g., TCP retransmissions).", difficulty = 1),
            Question(topicId = osi, questionText = "A hub operates at which OSI layer?", optionA = "Layer 1", optionB = "Layer 2", optionC = "Layer 3", optionD = "Layer 4", correctAnswer = "A", explanation = "Hubs are Layer 1 devices that simply repeat signals to all ports without any intelligence.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer is responsible for end-to-end logical communication between processes?", optionA = "Network", optionB = "Data Link", optionC = "Session", optionD = "Transport", correctAnswer = "D", explanation = "The Transport layer provides logical end-to-end communication between application processes on different hosts.", difficulty = 1),
            Question(topicId = osi, questionText = "SSL/TLS encryption is most often associated with which OSI layer?", optionA = "Session", optionB = "Transport", optionC = "Presentation", optionD = "Application", correctAnswer = "C", explanation = "SSL/TLS functions at the Presentation layer (Layer 6), handling data encryption before it reaches the Application layer.", difficulty = 1),
            Question(topicId = osi, questionText = "What is the PDU at the Transport layer called?", optionA = "Frame", optionB = "Packet", optionC = "Segment", optionD = "Bit", correctAnswer = "C", explanation = "The Transport layer PDU is called a segment (for TCP) or datagram (for UDP).", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer provides error detection using CRC in Ethernet frames?", optionA = "Physical", optionB = "Network", optionC = "Transport", optionD = "Data Link", correctAnswer = "D", explanation = "The Data Link layer uses the Frame Check Sequence (FCS/CRC) trailer in Ethernet frames for error detection.", difficulty = 1),
            Question(topicId = osi, questionText = "Port numbers are used at which OSI layer?", optionA = "Network", optionB = "Transport", optionC = "Session", optionD = "Application", correctAnswer = "B", explanation = "Port numbers are a Transport layer concept used to identify specific applications or services.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer is responsible for logical topology and media access control?", optionA = "Physical", optionB = "Network", optionC = "Data Link", optionD = "Transport", correctAnswer = "C", explanation = "The Data Link layer controls how devices share access to the physical medium (MAC) and defines logical topology.", difficulty = 1),
            Question(topicId = osi, questionText = "What does OSI stand for?", optionA = "Open System Interconnection", optionB = "Open Standard Interface", optionC = "Operational System Infrastructure", optionD = "Open Software Integration", correctAnswer = "A", explanation = "OSI stands for Open Systems Interconnection, a model developed by ISO for standardizing network communication.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer converts data formats so that applications can understand each other?", optionA = "Application", optionB = "Session", optionC = "Presentation", optionD = "Transport", correctAnswer = "C", explanation = "The Presentation layer translates data between formats (e.g., ASCII to EBCDIC) and handles encoding.", difficulty = 1),
            Question(topicId = osi, questionText = "Which two layers make up the TCP/IP 'Network Access' layer when mapped to OSI?", optionA = "Physical and Data Link", optionB = "Network and Transport", optionC = "Data Link and Network", optionD = "Physical and Network", correctAnswer = "A", explanation = "The TCP/IP Network Access layer combines OSI Layers 1 (Physical) and 2 (Data Link).", difficulty = 1),
            Question(topicId = osi, questionText = "A wireless access point (WAP) operates at which OSI layer?", optionA = "Layer 1", optionB = "Layer 2", optionC = "Layer 3", optionD = "Layer 4", correctAnswer = "B", explanation = "A WAP operates at Layer 2 (Data Link), bridging wireless and wired networks using MAC addresses.", difficulty = 1),
            Question(topicId = osi, questionText = "Which layer is responsible for routing packets across multiple networks?", optionA = "Data Link", optionB = "Transport", optionC = "Session", optionD = "Network", correctAnswer = "D", explanation = "The Network layer (Layer 3) handles logical addressing and routing of packets across multiple networks.", difficulty = 1)
        )

        // ── TCP vs UDP ────────────────────────────────────────────────────────
        val tcp = idMap.getValue("TCP vs UDP")
        list += listOf(
            Question(topicId = tcp, questionText = "Which protocol provides reliable, connection-oriented delivery?", optionA = "UDP", optionB = "ICMP", optionC = "TCP", optionD = "ARP", correctAnswer = "C", explanation = "TCP (Transmission Control Protocol) establishes a connection before sending data and guarantees delivery.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol is connectionless and does not guarantee delivery?", optionA = "TCP", optionB = "UDP", optionC = "FTP", optionD = "HTTP", correctAnswer = "B", explanation = "UDP (User Datagram Protocol) sends datagrams without establishing a connection or guaranteeing delivery.", difficulty = 1),
            Question(topicId = tcp, questionText = "What are the three messages in the TCP three-way handshake?", optionA = "SYN, FIN, ACK", optionB = "SYN, SYN-ACK, ACK", optionC = "ACK, SYN, RST", optionD = "SYN, ACK, FIN", correctAnswer = "B", explanation = "TCP connections start with SYN from the client, SYN-ACK from the server, and ACK from the client.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which port does HTTP use by default?", optionA = "443", optionB = "21", optionC = "80", optionD = "25", correctAnswer = "C", explanation = "HTTP (Hypertext Transfer Protocol) uses TCP port 80 by default.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol would you choose for live video streaming where speed matters more than reliability?", optionA = "TCP", optionB = "FTP", optionC = "UDP", optionD = "SMTP", correctAnswer = "C", explanation = "UDP is preferred for real-time applications like video streaming because its low overhead reduces latency.", difficulty = 1),
            Question(topicId = tcp, questionText = "What is the maximum size of a UDP datagram payload?", optionA = "1500 bytes", optionB = "65,507 bytes", optionC = "64 KB exactly", optionD = "Unlimited", correctAnswer = "B", explanation = "A UDP payload can be up to 65,507 bytes (65,535 minus 8-byte UDP header and 20-byte IP header).", difficulty = 1),
            Question(topicId = tcp, questionText = "Which TCP flag is set when a connection is being established?", optionA = "FIN", optionB = "RST", optionC = "SYN", optionD = "ACK", correctAnswer = "C", explanation = "The SYN (Synchronize) flag initiates a TCP connection.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol uses acknowledgements to confirm data receipt?", optionA = "UDP", optionB = "TCP", optionC = "ICMP", optionD = "ARP", correctAnswer = "B", explanation = "TCP sends ACK messages to confirm received data and retransmits if no acknowledgement is received.", difficulty = 1),
            Question(topicId = tcp, questionText = "DNS typically uses which transport protocol for standard queries?", optionA = "TCP", optionB = "UDP", optionC = "Both equally", optionD = "Neither", correctAnswer = "B", explanation = "DNS uses UDP port 53 for regular queries because it is faster; TCP is used for zone transfers and large responses.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which port does HTTPS use?", optionA = "80", optionB = "8080", optionC = "443", optionD = "22", correctAnswer = "C", explanation = "HTTPS (HTTP Secure) uses TCP port 443.", difficulty = 1),
            Question(topicId = tcp, questionText = "What mechanism does TCP use to avoid overwhelming a receiver?", optionA = "Port filtering", optionB = "Fragmentation", optionC = "Flow control (sliding window)", optionD = "TTL decrement", correctAnswer = "C", explanation = "TCP uses a sliding window mechanism to control how much data the sender can transmit before waiting for an ACK.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol would DNS-over-TCP use when a response exceeds 512 bytes?", optionA = "UDP", optionB = "TCP", optionC = "SCTP", optionD = "ICMP", correctAnswer = "B", explanation = "When DNS responses are too large for UDP, TCP port 53 is used to carry the response reliably.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which of the following is a characteristic of UDP but NOT TCP?", optionA = "Uses port numbers", optionB = "Operates at Layer 4", optionC = "Low overhead with no connection setup", optionD = "Carries application data", correctAnswer = "C", explanation = "UDP has minimal overhead because there is no connection establishment, acknowledgement, or retransmission.", difficulty = 1),
            Question(topicId = tcp, questionText = "What is the well-known port for SSH?", optionA = "23", optionB = "21", optionC = "22", optionD = "3389", correctAnswer = "C", explanation = "SSH (Secure Shell) uses TCP port 22 for encrypted remote administration.", difficulty = 1),
            Question(topicId = tcp, questionText = "TCP provides which of the following services? (Choose the best answer)", optionA = "Connectionless delivery", optionB = "Best-effort delivery", optionC = "Reliable, ordered data delivery", optionD = "Broadcast addressing", correctAnswer = "C", explanation = "TCP guarantees reliable, in-order delivery using sequence numbers, acknowledgements, and retransmissions.", difficulty = 1),
            Question(topicId = tcp, questionText = "What is the well-known port for Telnet?", optionA = "22", optionB = "23", optionC = "80", optionD = "443", correctAnswer = "B", explanation = "Telnet uses TCP port 23 for unencrypted remote access (largely replaced by SSH).", difficulty = 1),
            Question(topicId = tcp, questionText = "Which transport protocol is used by TFTP?", optionA = "TCP", optionB = "UDP", optionC = "ICMP", optionD = "IGMP", correctAnswer = "B", explanation = "TFTP (Trivial File Transfer Protocol) uses UDP port 69 because it is a simple, low-overhead file transfer.", difficulty = 1),
            Question(topicId = tcp, questionText = "What does the RST flag in TCP do?", optionA = "Starts a new connection", optionB = "Acknowledges data", optionC = "Abruptly resets/closes a connection", optionD = "Requests retransmission", correctAnswer = "C", explanation = "RST (Reset) abruptly terminates a TCP connection, unlike FIN which performs a graceful close.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol is used to transfer web pages securely?", optionA = "HTTP on port 80", optionB = "HTTPS on port 443", optionC = "FTP on port 21", optionD = "SFTP on port 22", correctAnswer = "B", explanation = "HTTPS uses TLS/SSL over TCP port 443 to encrypt web traffic.", difficulty = 1),
            Question(topicId = tcp, questionText = "VOIP (Voice over IP) traffic typically uses which transport protocol?", optionA = "TCP", optionB = "UDP", optionC = "SCTP", optionD = "GRE", correctAnswer = "B", explanation = "VoIP uses UDP (often via RTP) because real-time audio tolerates some loss but not the latency of TCP retransmissions.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which TCP/UDP port range is considered 'well-known ports'?", optionA = "1024–49151", optionB = "0–1023", optionC = "49152–65535", optionD = "1–255", correctAnswer = "B", explanation = "Well-known ports are 0–1023, assigned by IANA to common services like HTTP (80), SSH (22), and DNS (53).", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol is better suited for a file download that must arrive complete and in order?", optionA = "UDP", optionB = "ICMP", optionC = "TCP", optionD = "ARP", correctAnswer = "C", explanation = "TCP's reliability features (ACKs, retransmissions, sequencing) make it ideal when all data must arrive intact.", difficulty = 1),
            Question(topicId = tcp, questionText = "What port does FTP use for control messages?", optionA = "20", optionB = "21", optionC = "22", optionD = "25", correctAnswer = "B", explanation = "FTP uses TCP port 21 for control (commands) and port 20 for data transfer in active mode.", difficulty = 1),
            Question(topicId = tcp, questionText = "A TCP segment that carries no data but only acknowledges receipt is called a?", optionA = "FIN segment", optionB = "RST segment", optionC = "Pure ACK", optionD = "SYN segment", correctAnswer = "C", explanation = "A pure ACK is a TCP segment with the ACK flag set but no payload data.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which header field in UDP gives the total length of the UDP header and data?", optionA = "Checksum", optionB = "Source Port", optionC = "Length", optionD = "Sequence Number", correctAnswer = "C", explanation = "The UDP Length field specifies the total length of the UDP header (8 bytes) plus the data payload.", difficulty = 1),
            Question(topicId = tcp, questionText = "What is the main disadvantage of TCP compared to UDP?", optionA = "No port numbers", optionB = "Higher overhead and latency due to connection management", optionC = "Cannot carry large payloads", optionD = "Does not work over IP", correctAnswer = "B", explanation = "TCP's reliability mechanisms (handshake, ACKs, retransmissions) add overhead and latency compared to UDP.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which transport protocol does SNMP use?", optionA = "TCP", optionB = "UDP", optionC = "GRE", optionD = "OSPF", correctAnswer = "B", explanation = "SNMP (Simple Network Management Protocol) uses UDP port 161 for queries and port 162 for traps.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which port does SMTP use for sending email?", optionA = "110", optionB = "143", optionC = "25", optionD = "587", correctAnswer = "C", explanation = "SMTP (Simple Mail Transfer Protocol) uses TCP port 25 for server-to-server email delivery.", difficulty = 1),
            Question(topicId = tcp, questionText = "What is the size of a UDP header?", optionA = "20 bytes", optionB = "12 bytes", optionC = "8 bytes", optionD = "32 bytes", correctAnswer = "C", explanation = "The UDP header is 8 bytes and contains Source Port, Destination Port, Length, and Checksum fields.", difficulty = 1),
            Question(topicId = tcp, questionText = "Which protocol is stateful — meaning it tracks the state of each connection?", optionA = "UDP", optionB = "TCP", optionC = "ICMP", optionD = "ARP", correctAnswer = "B", explanation = "TCP is stateful; it maintains connection state (ESTABLISHED, TIME_WAIT, etc.) throughout the session.", difficulty = 1)
        )

        // ── IP Addressing ─────────────────────────────────────────────────────
        val ip = idMap.getValue("IP Addressing")
        list += listOf(
            Question(topicId = ip, questionText = "How many bits are in an IPv4 address?", optionA = "16", optionB = "32", optionC = "64", optionD = "128", correctAnswer = "B", explanation = "IPv4 addresses are 32 bits long, written as four 8-bit octets in dotted decimal notation.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the default subnet mask for a Class C network?", optionA = "255.0.0.0", optionB = "255.255.0.0", optionC = "255.255.255.0", optionD = "255.255.255.128", correctAnswer = "C", explanation = "Class C networks use a /24 mask (255.255.255.0), leaving 8 bits for host addresses.", difficulty = 1),
            Question(topicId = ip, questionText = "Which IP address range is reserved for private Class A networks?", optionA = "172.16.0.0 – 172.31.255.255", optionB = "192.168.0.0 – 192.168.255.255", optionC = "10.0.0.0 – 10.255.255.255", optionD = "127.0.0.0 – 127.255.255.255", correctAnswer = "C", explanation = "10.0.0.0/8 is the RFC 1918 private range for Class A, giving over 16 million host addresses.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the broadcast address of the network 192.168.1.0/24?", optionA = "192.168.1.0", optionB = "192.168.1.254", optionC = "192.168.1.255", optionD = "192.168.0.255", correctAnswer = "C", explanation = "The broadcast address is the last address in the subnet, where all host bits are 1s — 192.168.1.255.", difficulty = 1),
            Question(topicId = ip, questionText = "Which address class was originally designed for large networks with millions of hosts?", optionA = "Class A", optionB = "Class B", optionC = "Class C", optionD = "Class D", correctAnswer = "A", explanation = "Class A (1.0.0.0 – 126.255.255.255) uses an 8-bit network portion and 24-bit host portion.", difficulty = 1),
            Question(topicId = ip, questionText = "What does CIDR stand for?", optionA = "Classless Inter-Domain Routing", optionB = "Centralized IP Data Routing", optionC = "Common Internet Data Registry", optionD = "Classful IP Designation Routing", correctAnswer = "A", explanation = "CIDR allows flexible subnet sizes by specifying the prefix length (e.g., /24), replacing rigid classful addressing.", difficulty = 1),
            Question(topicId = ip, questionText = "How many usable host addresses does a /24 subnet provide?", optionA = "254", optionB = "255", optionC = "256", optionD = "252", correctAnswer = "A", explanation = "A /24 has 256 addresses; subtract 1 for the network address and 1 for broadcast = 254 usable hosts.", difficulty = 1),
            Question(topicId = ip, questionText = "Which address is used to send a packet to all hosts on a local network?", optionA = "127.0.0.1", optionB = "0.0.0.0", optionC = "255.255.255.255", optionD = "192.168.1.1", correctAnswer = "C", explanation = "255.255.255.255 is the limited broadcast address, sent to all hosts on the local segment.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the loopback address in IPv4?", optionA = "0.0.0.0", optionB = "127.0.0.1", optionC = "192.168.0.1", optionD = "255.255.255.255", correctAnswer = "B", explanation = "127.0.0.1 is the loopback address used to test the TCP/IP stack on the local host.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the subnet mask for a /26 prefix?", optionA = "255.255.255.192", optionB = "255.255.255.128", optionC = "255.255.255.224", optionD = "255.255.255.240", correctAnswer = "A", explanation = "/26 means 26 bits are set to 1 in the mask: 11111111.11111111.11111111.11000000 = 255.255.255.192.", difficulty = 1),
            Question(topicId = ip, questionText = "Which of the following is a valid private IP range defined by RFC 1918?", optionA = "172.32.0.0/12", optionB = "172.16.0.0/12", optionC = "192.169.0.0/16", optionD = "10.0.0.0/16", correctAnswer = "B", explanation = "172.16.0.0/12 (172.16.0.0 – 172.31.255.255) is one of the three RFC 1918 private ranges.", difficulty = 1),
            Question(topicId = ip, questionText = "How many bits make up an IPv6 address?", optionA = "32", optionB = "64", optionC = "128", optionD = "256", correctAnswer = "C", explanation = "IPv6 uses 128-bit addresses, written as eight groups of four hexadecimal digits.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the network address of 192.168.10.130/25?", optionA = "192.168.10.0", optionB = "192.168.10.128", optionC = "192.168.10.1", optionD = "192.168.10.255", correctAnswer = "B", explanation = "/25 splits the last octet into two halves (0–127 and 128–255). Host 130 falls in the 128 subnet.", difficulty = 1),
            Question(topicId = ip, questionText = "Which protocol automatically assigns IP addresses to hosts?", optionA = "ARP", optionB = "DNS", optionC = "DHCP", optionD = "NAT", correctAnswer = "C", explanation = "DHCP (Dynamic Host Configuration Protocol) dynamically assigns IP addresses and other network settings.", difficulty = 1),
            Question(topicId = ip, questionText = "A /30 subnet is commonly used for which purpose?", optionA = "Large LAN segments", optionB = "Point-to-point WAN links", optionC = "Server farms", optionD = "VLAN management", correctAnswer = "B", explanation = "/30 provides 4 addresses (2 usable), which is ideal for point-to-point links between two routers.", difficulty = 1),
            Question(topicId = ip, questionText = "What is the binary representation of the decimal number 192?", optionA = "10110000", optionB = "11000000", optionC = "11100000", optionD = "10100000", correctAnswer = "B", explanation = "192 = 128 + 64 = 11000000 in binary.", difficulty = 1),
            Question(topicId = ip, questionText = "The 169.254.0.0/16 range is used for which purpose?", optionA = "Loopback testing", optionB = "Multicast addressing", optionC = "APIPA (Automatic Private IP Addressing)", optionD = "Public internet routing", correctAnswer = "C", explanation = "APIPA assigns addresses in 169.254.0.0/16 when a host cannot reach a DHCP server.", difficulty = 1),
            Question(topicId = ip, questionText = "How many subnets does a /27 mask create from a /24 block?", optionA = "2", optionB = "4", optionC = "8", optionD = "16", correctAnswer = "C", explanation = "/27 borrows 3 bits from the host portion of a /24, creating 2³ = 8 subnets of 32 addresses each.", difficulty = 1),
            Question(topicId = ip, questionText = "Which address identifies the network itself and cannot be assigned to a host?", optionA = "First usable address", optionB = "Network address (all host bits = 0)", optionC = "Broadcast address", optionD = "Gateway address", correctAnswer = "B", explanation = "The network address has all host bits set to 0 and represents the subnet itself, not any individual host.", difficulty = 1),
